__global__ void kernel_gpu_cuda(	par_str parms,
									dim_str dim,
									box_str* box,
									FOUR_VECTOR* rv,
									fp* qv,
									FOUR_VECTOR* fv)
{
	// thread identifiers
	int l = blockIdx.x * blockDim.x + threadIdx.x;

	// home box - box parameters
	int first_i;
	FOUR_VECTOR* rA;
	FOUR_VECTOR* fA;

	// neighbor box - box parameters
	int pointer;
	int first_j; 
	FOUR_VECTOR* rB;
	fp* qB;

	// common
	fp r2; 
	fp u2;
	fp fs;
	fp vij;
	fp fxij,fyij,fzij;
	THREE_VECTOR d;

	if (l < dim.number_boxes) {

		// home box - box parameters
		first_i = box[l].offset;												// offset to common arrays

		// home box - distance, force, charge and type parameters from common arrays
		rA = &rv[first_i];
		fA = &fv[first_i];

		// Do for the # of (home+neighbor) boxes
		for (int k=0; k<(1+box[l].nn); k++) 
		{

			// neighbor box - get pointer to the right box
			if(k==0){
				pointer = l;													// set first box to be processed to home box
			}
			else{
				pointer = box[l].nei[k-1].number;							// remaining boxes are neighbor boxes
			}

			// neighbor box - box parameters
			first_j = box[pointer].offset; 

			// neighbor box - distance, force, charge and type parameters
			rB = &rv[first_j];
			qB = &qv[first_j];

			// Do for the # of particles in home box
			for (int i=0; i<NUMBER_PAR_PER_BOX; i=i+1){

				// do for the # of particles in current (home or neighbor) box
				for (int j=0; j<NUMBER_PAR_PER_BOX; j=j+1){

					// coefficients
					r2 = rA[i].v + rB[j].v - (rA[i].x * rB[j].x + rA[i].y * rB[j].y + rA[i].z * rB[j].z); 
					u2 = 2.0*parms.alpha*parms.alpha*r2;
					vij= exp(-u2);
					fs = 2.*vij;
					d.x = rA[i].x  - rB[j].x; 
					d.y = rA[i].y  - rB[j].y; 
					d.z = rA[i].z  - rB[j].z; 
					fxij=fs*d.x;
					fyij=fs*d.y;
					fzij=fs*d.z;

					// forces
					fA[i].v +=  qB[j]*vij;
					fA[i].x +=  qB[j]*fxij;
					fA[i].y +=  qB[j]*fyij;
					fA[i].z +=  qB[j]*fzij;

				} // for j

			} // for i

		} // for k

	} // for l

}

extern "C" void kernel_gpu_cuda_wrapper(	par_str parms_cpu,
								dim_str dim_cpu,
								box_str* box_cpu,
								FOUR_VECTOR* rv_cpu,
								fp* qv_cpu,
								FOUR_VECTOR* fv_cpu)
{
	// Allocate device memory
	par_str* d_parms;
	dim_str* d_dim;
	box_str* d_box;
	FOUR_VECTOR* d_rv;
	fp* d_qv;
	FOUR_VECTOR* d_fv;

	size_t parms_size = sizeof(par_str);
	size_t dim_size = sizeof(dim_str);
	size_t box_size = dim_cpu.number_boxes * sizeof(box_str);
	size_t rv_size = dim_cpu.space_elem * sizeof(FOUR_VECTOR);
	size_t qv_size = dim_cpu.space_elem * sizeof(fp);
	size_t fv_size = dim_cpu.space_elem * sizeof(FOUR_VECTOR);

	cudaMalloc((void**)&d_parms, parms_size);
	cudaMalloc((void**)&d_dim, dim_size);
	cudaMalloc((void**)&d_box, box_size);
	cudaMalloc((void**)&d_rv, rv_size);
	cudaMalloc((void**)&d_qv, qv_size);
	cudaMalloc((void**)&d_fv, fv_size);

	// Copy data from host to device
	cudaMemcpy(d_parms, &parms_cpu, parms_size, cudaMemcpyHostToDevice);
	cudaMemcpy(d_dim, &dim_cpu, dim_size, cudaMemcpyHostToDevice);
	cudaMemcpy(d_box, box_cpu, box_size, cudaMemcpyHostToDevice);
	cudaMemcpy(d_rv, rv_cpu, rv_size, cudaMemcpyHostToDevice);
	cudaMemcpy(d_qv, qv_cpu, qv_size, cudaMemcpyHostToDevice);
	cudaMemcpy(d_fv, fv_cpu, fv_size, cudaMemcpyHostToDevice);

	// Launch kernel
	int num_blocks = (dim_cpu.number_boxes + NUMBER_THREADS - 1) / NUMBER_THREADS;
	kernel_gpu_cuda<<<num_blocks, NUMBER_THREADS>>>(*d_parms, *d_dim, d_box, d_rv, d_qv, d_fv);

	// Copy data from device to host
	cudaMemcpy(fv_cpu, d_fv, fv_size, cudaMemcpyDeviceToHost);

	// Free device memory
	cudaFree(d_parms);
	cudaFree(d_dim);
	cudaFree(d_box);
	cudaFree(d_rv);
	cudaFree(d_qv);
	cudaFree(d_fv);
}

